// DashboardScreen.jsx — with Save as Image + PDF export

import { useRef, useState } from "react";
import ChartCard from "./ChartCard";
import InsightPanel from "./InsightPanel";
import VoicePanel from "./VoicePanel";

// ── Load html2canvas from CDN dynamically ────────────────────────────────────
function loadHtml2Canvas() {
  return new Promise((resolve, reject) => {
    if (window.html2canvas) { resolve(window.html2canvas); return; }
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
    script.onload = () => resolve(window.html2canvas);
    script.onerror = reject;
    document.head.appendChild(script);
  });
}

export default function DashboardScreen({ data, sessionId, colorSchema, onReset }) {
  const { dashboard_title, charts, insights, summary, kpi_coverage, total_kpis_generated } = data;
  const dashboardRef = useRef(null);
  const [exporting, setExporting] = useState(false);
  const [exportType, setExportType] = useState("");
  const [showExportMenu, setShowExportMenu] = useState(false);

  const voiceContext = charts.map((c) => ({
    kpi: c.kpi, chart_type: c.chart_type, data: c.data.slice(0, 20),
  }));

  // ── Export as PNG Image ───────────────────────────────────────────────────
  const exportAsImage = async () => {
    setShowExportMenu(false);
    setExporting(true);
    setExportType("image");
    try {
      const html2canvas = await loadHtml2Canvas();
      const element = dashboardRef.current;

      const canvas = await html2canvas(element, {
        backgroundColor: "#0a0c10",
        scale: 2,                    // 2x resolution for crisp image
        useCORS: true,
        allowTaint: true,
        logging: false,
        windowWidth: element.scrollWidth,
        windowHeight: element.scrollHeight,
      });

      // Download as PNG
      const link = document.createElement("a");
      link.download = `${dashboard_title.replace(/\s+/g, "_")}_dashboard.png`;
      link.href = canvas.toDataURL("image/png");
      link.click();
    } catch (err) {
      console.error("Export failed:", err);
      alert("Image export failed. Please try again.");
    } finally {
      setExporting(false);
      setExportType("");
    }
  };

  // ── Export as PDF ─────────────────────────────────────────────────────────
  const exportAsPDF = async () => {
    setShowExportMenu(false);
    setExporting(true);
    setExportType("pdf");
    try {
      const html2canvas = await loadHtml2Canvas();
      const element = dashboardRef.current;

      const canvas = await html2canvas(element, {
        backgroundColor: "#0a0c10",
        scale: 1.5,
        useCORS: true,
        allowTaint: true,
        logging: false,
        windowWidth: element.scrollWidth,
        windowHeight: element.scrollHeight,
      });

      const imgData = canvas.toDataURL("image/png");
      const imgWidth = canvas.width;
      const imgHeight = canvas.height;

      // Open a new print window with the image
      const printWindow = window.open("", "_blank");
      printWindow.document.write(`
        <!DOCTYPE html>
        <html>
          <head>
            <title>${dashboard_title}</title>
            <style>
              * { margin: 0; padding: 0; box-sizing: border-box; }
              body { background: #0a0c10; }
              .page {
                width: 100%;
                page-break-inside: avoid;
              }
              img {
                width: 100%;
                height: auto;
                display: block;
              }
              .header {
                background: #0f1117;
                color: #e8eaf0;
                padding: 20px 32px;
                font-family: sans-serif;
                border-bottom: 1px solid #1e2333;
                display: flex;
                justify-content: space-between;
                align-items: center;
              }
              .header h1 { font-size: 20px; font-weight: 800; }
              .header p { font-size: 12px; color: #8891a8; margin-top: 4px; }
              .meta { font-size: 12px; color: #8891a8; text-align: right; }
              @media print {
                body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                @page { margin: 0; size: A4 landscape; }
              }
            </style>
          </head>
          <body>
            <div class="header">
              <div>
                <h1>📊 ${dashboard_title}</h1>
                <p>Generated by Talking BI • ${new Date().toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" })}</p>
              </div>
              <div class="meta">
                <div>${total_kpis_generated} Charts</div>
                <div>KPI Coverage: ${kpi_coverage}%</div>
              </div>
            </div>
            <div class="page">
              <img src="${imgData}" />
            </div>
            <script>
              window.onload = function() {
                setTimeout(function() { window.print(); }, 500);
              };
            </script>
          </body>
        </html>
      `);
      printWindow.document.close();
    } catch (err) {
      console.error("PDF export failed:", err);
      alert("PDF export failed. Please try again.");
    } finally {
      setExporting(false);
      setExportType("");
    }
  };

  return (
    <div style={styles.screen}>

      {/* ── Top Bar ───────────────────────────────────────────────────────── */}
      <div style={styles.topBar}>
        <div style={styles.topLeft}>
          <div style={styles.logoMini}>
            <svg width="18" height="18" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="13" stroke="#4f8ef7" strokeWidth="1.5"/>
              <path d="M8 18 L12 10 L16 15 L20 8" stroke="#4f8ef7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="8" r="2" fill="#7c5cfc"/>
            </svg>
          </div>
          <h1 style={styles.dashTitle}>{dashboard_title}</h1>
        </div>

        <div style={styles.statRow}>
          {/* Stats */}
          <div style={styles.stat}>
            <span style={styles.statNum}>{total_kpis_generated}</span>
            <span style={styles.statLabel}>Charts</span>
          </div>
          <div style={styles.statDivider} />
          <div style={styles.stat}>
            <span style={{ ...styles.statNum, color: kpi_coverage >= 80 ? "var(--success)" : "var(--warn)" }}>
              {kpi_coverage}%
            </span>
            <span style={styles.statLabel}>KPI Coverage</span>
          </div>
          <div style={styles.statDivider} />

          {/* ── Export Button with dropdown ────────────────────────────── */}
          <div style={styles.exportWrap}>
            <button
              style={{ ...styles.exportBtn, ...(exporting ? styles.exportBtnDisabled : {}) }}
              onClick={() => !exporting && setShowExportMenu((v) => !v)}
              disabled={exporting}
            >
              {exporting ? (
                <>
                  <span style={styles.spinner} />
                  {exportType === "pdf" ? "Saving PDF..." : "Saving Image..."}
                </>
              ) : (
                <>
                  {/* Download icon */}
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                    <path d="M7 1v8M4 6l3 3 3-3M2 10v2a1 1 0 001 1h8a1 1 0 001-1v-2" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                  Export
                  <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{ marginLeft: "2px" }}>
                    <path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
                  </svg>
                </>
              )}
            </button>

            {/* Dropdown menu */}
            {showExportMenu && !exporting && (
              <div style={styles.exportMenu}>
                <button style={styles.exportMenuItem} onClick={exportAsImage}>
                  <div style={styles.menuIconWrap}>
                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                      <rect x="1" y="1" width="14" height="14" rx="2" stroke="#4f8ef7" strokeWidth="1.3"/>
                      <circle cx="5" cy="5.5" r="1.5" fill="#4f8ef7"/>
                      <path d="M1 11l4-4 3 3 2-2 5 5" stroke="#4f8ef7" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                  </div>
                  <div>
                    <div style={styles.menuItemTitle}>Save as PNG</div>
                    <div style={styles.menuItemSub}>High-resolution image (2x)</div>
                  </div>
                </button>

                <div style={styles.menuDivider} />

                <button style={styles.exportMenuItem} onClick={exportAsPDF}>
                  <div style={styles.menuIconWrap}>
                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                      <rect x="2" y="1" width="10" height="14" rx="1.5" stroke="#f7a84f" strokeWidth="1.3"/>
                      <path d="M5 5h6M5 8h6M5 11h4" stroke="#f7a84f" strokeWidth="1.3" strokeLinecap="round"/>
                      <path d="M10 1v4h4" stroke="#f7a84f" strokeWidth="1.3" strokeLinecap="round"/>
                    </svg>
                  </div>
                  <div>
                    <div style={{ ...styles.menuItemTitle, color: "#f7a84f" }}>Save as PDF</div>
                    <div style={styles.menuItemSub}>Print-ready landscape PDF</div>
                  </div>
                </button>
              </div>
            )}
          </div>

          <div style={styles.statDivider} />

          {/* New Dashboard button */}
          <button style={styles.resetBtn} onClick={onReset}>
            <svg width="13" height="13" viewBox="0 0 14 14" fill="none">
              <path d="M2 7a5 5 0 015-5 5 5 0 014.9 4M12 2v4H8" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
            New
          </button>
        </div>
      </div>

      {/* ── Body ──────────────────────────────────────────────────────────── */}
      <div style={styles.body}>

        {/* Charts grid — this is what gets exported */}
        <div style={styles.mainCol}>
          <div ref={dashboardRef} style={styles.exportArea}>
            <div style={styles.chartsGrid}>
              {charts.map((chart, i) => (
                <ChartCard
                  key={chart.kpi}
                  chart={chart}
                  colorSchema={colorSchema}
                  index={i}
                />
              ))}
            </div>

            {/* Summary shown in export */}
            {summary && (
              <div style={styles.summaryExport}>
                <div style={styles.summaryExportLabel}>📋 Executive Summary</div>
                <p style={styles.summaryExportText}>{summary}</p>
              </div>
            )}
          </div>
        </div>

        {/* Right sidebar */}
        <div style={styles.sideCol}>
          <VoicePanel sessionId={sessionId} dashboardContext={voiceContext} />
          <InsightPanel insights={insights} summary={summary} />
        </div>
      </div>

      {/* Click outside to close menu */}
      {showExportMenu && (
        <div
          style={styles.menuOverlay}
          onClick={() => setShowExportMenu(false)}
        />
      )}
    </div>
  );
}

const styles = {
  screen: { minHeight: "100vh", display: "flex", flexDirection: "column" },
  topBar: {
    padding: "14px 28px",
