  logoMini: {
    width: "34px", height: "34px",
    background: "rgba(79,142,247,0.1)", border: "1px solid rgba(79,142,247,0.2)",
    borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center",
  },
  dashTitle: { fontSize: "18px", fontWeight: 800, color: "#fff", letterSpacing: "-0.3px" },
  statRow: { display: "flex", alignItems: "center", gap: "16px" },
  stat: { display: "flex", flexDirection: "column", alignItems: "center", gap: "2px" },
  statNum: { fontSize: "18px", fontWeight: 800, color: "var(--accent)", fontFamily: "'Syne', sans-serif" },
  statLabel: { fontSize: "10px", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.07em" },
